namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private readonly List<Notification> _notifications;
    private int _nextId;

    public NotificationService()
    {
        _notifications = new List<Notification>
        {
            new(1, "Welcome to the notification center!", DateTime.UtcNow.AddMinutes(-30)),
            new(2, "Your profile was updated successfully.", DateTime.UtcNow.AddMinutes(-20)),
            new(3, "New comment on your post.", DateTime.UtcNow.AddMinutes(-10)),
        };
        _nextId = 4;
    }

    /// <summary>Returns all notifications available at this moment.</summary>
    public Task<List<Notification>> GetNotificationsAsync()
    {
        lock (_notifications)
        {
            return Task.FromResult(_notifications.ToList());
        }
    }

    /// <summary>Returns only notifications newer than the given timestamp.</summary>
    public Task<List<Notification>> GetNotificationsSinceAsync(DateTime since)
    {
        // Simulate a new notification arriving roughly every 10 seconds.
        MaybeAddFakeNotification();

        lock (_notifications)
        {
            return Task.FromResult(
                _notifications.Where(n => n.Timestamp > since).ToList());
        }
    }

    private void MaybeAddFakeNotification()
    {
        lock (_notifications)
        {
            var last = _notifications.MaxBy(n => n.Timestamp);
            if (last is not null && DateTime.UtcNow - last.Timestamp > TimeSpan.FromSeconds(10))
            {
                var id = _nextId++;
                _notifications.Add(new Notification(
                    id,
                    $"New event #{id} just happened!",
                    DateTime.UtcNow));
            }
        }
    }
}

@page "/notifications"
@rendermode @(new InteractiveServerRenderMode(prerender: true))
@using NotificationsApp.Services
@inject NotificationService NotificationSvc
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill">@_notifications.Count</span>
</h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in _notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> _notifications = new();
    private CancellationTokenSource? _cts;
    private DateTime _lastCheck;

    // Runs during SSR *and* when the component re-initializes on the
    // interactive circuit. The flag _initializedOnce ensures we only
    // fetch the seed data once (during SSR); on the interactive pass the
    // persisted state is already present.
    protected override async Task OnInitializedAsync()
    {
        // Always load from the service – during prerender this gives us
        // the fast HTML; during the interactive init the same call is
        // cheap (in-memory list) and guarantees the component is never
        // empty if persisted-state were to be unavailable.
        _notifications = await NotificationSvc.GetNotificationsAsync();
        _lastCheck = _notifications.Count > 0
            ? _notifications.Max(n => n.Timestamp)
            : DateTime.UtcNow;
    }

    // OnAfterRenderAsync with firstRender == true fires ONLY on the
    // interactive circuit – never during static SSR – so it is the
    // perfect place to kick off the polling loop.
    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);

                var newer = await NotificationSvc.GetNotificationsSinceAsync(_lastCheck);
                if (newer.Count > 0)
                {
                    _notifications.AddRange(newer);
                    _lastCheck = newer.Max(n => n.Timestamp);
                    await InvokeAsync(StateHasChanged);
                }
            }
            catch (TaskCanceledException)
            {
                // Expected on dispose – exit gracefully.
                break;
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

